import{_ as s,o as i,c as e,a2 as n}from"./chunks/framework.DCVnL8g5.js";const u=JSON.parse('{"title":"Arquitectura interna","description":"","frontmatter":{},"headers":[],"relativePath":"bases-de-datos/redis/10-arquitectura-interna.md","filePath":"bases-de-datos/redis/10-arquitectura-interna.md","lastUpdated":1782521464000}'),t={name:"bases-de-datos/redis/10-arquitectura-interna.md"};function l(o,a,p,r,c,d){return i(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="arquitectura-interna" tabindex="-1">Arquitectura interna <a class="header-anchor" href="#arquitectura-interna" aria-label="Permalink to &quot;Arquitectura interna&quot;">​</a></h1><p>Redis es rapido porque su diseno evita muchas capas: mantiene el dataset en memoria, ejecuta comandos de forma muy eficiente y usa estructuras de datos optimizadas para cada tipo.</p><h2 id="modelo-general" tabindex="-1">Modelo general <a class="header-anchor" href="#modelo-general" aria-label="Permalink to &quot;Modelo general&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C[&quot;Clientes&quot;] --&gt; S[&quot;Redis server&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  S --&gt; M[&quot;Memoria&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  S --&gt; P[&quot;Persistencia&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  S --&gt; R[&quot;Replicas&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  P --&gt; AOF[&quot;AOF&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  P --&gt; RDB[&quot;RDB snapshots&quot;]</span></span></code></pre></div><h2 id="proceso-principal" tabindex="-1">Proceso principal <a class="header-anchor" href="#proceso-principal" aria-label="Permalink to &quot;Proceso principal&quot;">​</a></h2><p>Redis usa un proceso servidor que atiende conexiones, interpreta comandos y modifica estructuras en memoria.</p><p>Aunque Redis puede usar hilos auxiliares para algunas tareas, el modelo mental importante es que los comandos se procesan de forma ordenada. Eso simplifica la atomicidad: un comando individual no se entremezcla con otro.</p><h2 id="event-loop" tabindex="-1">Event loop <a class="header-anchor" href="#event-loop" aria-label="Permalink to &quot;Event loop&quot;">​</a></h2><p>Redis usa un bucle de eventos para manejar conexiones de red sin crear un hilo por cliente.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  participant C as Cliente</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  participant E as Event loop</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  participant D as Dataset</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C-&gt;&gt;E: SET user:1 &quot;Iago&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  E-&gt;&gt;D: Escribe valor</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  D--&gt;&gt;E: OK</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  E--&gt;&gt;C: OK</span></span></code></pre></div><h2 id="dataset-en-memoria" tabindex="-1">Dataset en memoria <a class="header-anchor" href="#dataset-en-memoria" aria-label="Permalink to &quot;Dataset en memoria&quot;">​</a></h2><p>Redis guarda claves y valores en memoria. Cada clave apunta a un objeto Redis con tipo, encoding interno y metadata.</p><p>Tipos principales:</p><ul><li>Strings.</li><li>Hashes.</li><li>Lists.</li><li>Sets.</li><li>Sorted sets.</li><li>Streams.</li><li>HyperLogLog.</li><li>Bitmaps.</li></ul><h2 id="encodings-internos" tabindex="-1">Encodings internos <a class="header-anchor" href="#encodings-internos" aria-label="Permalink to &quot;Encodings internos&quot;">​</a></h2><p>Redis puede representar un mismo tipo de dato con estructuras internas distintas segun tamano y forma.</p><p>Ejemplos:</p><ul><li>Hash pequeno: representacion compacta.</li><li>Hash grande: tabla hash.</li><li>Sorted set pequeno: representacion compacta.</li><li>Sorted set grande: skiplist + hash.</li></ul><p>No necesitas controlar esto todos los dias, pero explica por que cambiar cardinalidades puede afectar memoria y rendimiento.</p><h2 id="operaciones-o-1-o-log-n-y-o-n" tabindex="-1">Operaciones O(1), O(log n) y O(n) <a class="header-anchor" href="#operaciones-o-1-o-log-n-y-o-n" aria-label="Permalink to &quot;Operaciones O(1), O(log n) y O(n)&quot;">​</a></h2><p>No todos los comandos cuestan igual.</p><p>Ejemplos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET clave              O(1)</span></span>
<span class="line"><span>SET clave valor        O(1)</span></span>
<span class="line"><span>HGET hash campo        O(1)</span></span>
<span class="line"><span>ZADD ranking score id  O(log n)</span></span>
<span class="line"><span>LRANGE lista 0 -1      O(n)</span></span>
<span class="line"><span>KEYS *                 O(n)</span></span></code></pre></div><p>En produccion, evita comandos que recorren todo el dataset.</p><h2 id="expiraciones" tabindex="-1">Expiraciones <a class="header-anchor" href="#expiraciones" aria-label="Permalink to &quot;Expiraciones&quot;">​</a></h2><p>Redis permite asociar TTL a claves.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> token:abc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;user-1&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> EX</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 900</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">TTL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> token:abc</span></span></code></pre></div><p>Redis elimina claves expiradas de dos formas:</p><ul><li>Eliminacion pasiva cuando se accede a una clave caducada.</li><li>Eliminacion activa muestreando claves con TTL.</li></ul><h2 id="persistencia" tabindex="-1">Persistencia <a class="header-anchor" href="#persistencia" aria-label="Permalink to &quot;Persistencia&quot;">​</a></h2><p>Redis puede persistir datos, pero su fortaleza sigue siendo la velocidad en memoria.</p><p>Opciones:</p><ul><li>RDB: snapshots periodicos.</li><li>AOF: log de comandos de escritura.</li><li>RDB + AOF: combinacion comun para mas seguridad.</li></ul><h2 id="replicacion" tabindex="-1">Replicacion <a class="header-anchor" href="#replicacion" aria-label="Permalink to &quot;Replicacion&quot;">​</a></h2><p>Una replica recibe datos del primario.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  P[&quot;Primary&quot;] --&gt; R1[&quot;Replica 1&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  P --&gt; R2[&quot;Replica 2&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  R1 --&gt; C1[&quot;Lecturas opcionales&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  R2 --&gt; C2[&quot;Lecturas opcionales&quot;]</span></span></code></pre></div><p>La replicacion mejora disponibilidad y puede descargar lecturas, pero no sustituye backups.</p><h2 id="latencia" tabindex="-1">Latencia <a class="header-anchor" href="#latencia" aria-label="Permalink to &quot;Latencia&quot;">​</a></h2><p>La latencia puede venir de:</p><ul><li>Comandos pesados.</li><li>Memoria insuficiente.</li><li>Swapping.</li><li>Red.</li><li>Persistencia mal configurada.</li><li>Forks para snapshots en instancias grandes.</li></ul><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Conoce la complejidad de los comandos que usas.</li><li>Evita <code>KEYS</code> en produccion; usa <code>SCAN</code>.</li><li>Mantén Redis con memoria suficiente para evitar swap.</li><li>Decide persistencia segun criticidad del dato.</li><li>Monitoriza latencia, memoria y comandos lentos.</li></ul>`,42)])])}const m=s(t,[["render",l]]);export{u as __pageData,m as default};
